using Microsoft.AspNetCore.Authentication; using Microsoft.AspNetCore.Authentication.Cookies; using Microsoft.AspNetCore.Mvc; using SV22T1020494.BusinessLayers; using SV22T1020494.DataLayers.SQLServer; using SV22T1020494.Models.Security; using System.Security.Claims; using System.Threading.Tasks; using System.Security.Cryptography; using System.Text;  namespace SV22T1020494.Shop.Controllers {     /// <summary>     /// Xử lý các hành động liên quan đến tài khoản khách hàng: đăng nhập, đăng ký,     /// quản lý tài khoản, xem đơn hàng và đổi mật khẩu.      /// </summary>     public class AccountController : Controller     {         private readonly CustomerAccountRepository _customerAccountRepo;          public AccountController()         {             _customerAccountRepo = new CustomerAccountRepository(Configuration.ConnectionString);         }         /// <summary>         /// Đăng nhập         /// </summary>         /// <param name="returnUrl"></param>         /// <returns></returns>         [HttpGet]         public IActionResult Login(string returnUrl = null)         {             ViewData["ReturnUrl"] = returnUrl;             var vm = new SV22T1020494.Shop.Models.LoginViewModel { ReturnUrl = returnUrl };             return View(vm);         }          /// <summary>         /// POST Đăng nhập         /// </summary>         /// <param name="model"></param>         /// <returns></returns>         [HttpPost]         [ValidateAntiForgeryToken]         public async Task<IActionResult> Login(SV22T1020494.Shop.Models.LoginViewModel model)         {             ViewData["ReturnUrl"] = model?.ReturnUrl;             if (model == null || string.IsNullOrWhiteSpace(model.Email) || string.IsNullOrWhiteSpace(model.Password))             {                 ModelState.AddModelError(string.Empty, "Vui lòng nhập email và mật khẩu.");                 return View(model);             }              var row = await _customerAccountRepo.GetCustomerByEmailAsync(model.Email);             if (row == null)             {                 ModelState.AddModelError(string.Empty, "Email hoặc mật khẩu không đúng.");                 return View(model);             }              bool isLocked = false;             try { isLocked = (bool)row.IsLocked; } catch { isLocked = false; }             if (isLocked)             {                 ModelState.AddModelError(string.Empty, "Tài khoản này đã bị khoá.");                 return View(model);             }              var storedPassword = (row.Password ?? string.Empty) as string;             var input = model.Password ?? string.Empty;              string ComputeMd5(string s)             {                 using var md5 = MD5.Create();                 var bytes = Encoding.UTF8.GetBytes(s);                 var hash = md5.ComputeHash(bytes);                 var sb = new StringBuilder();                 foreach (var b in hash) sb.Append(b.ToString("x2"));                 return sb.ToString();             }              var inputMd5 = ComputeMd5(input);              var passwordMatch = string.Equals(storedPassword, input, System.StringComparison.Ordinal)                  || string.Equals(storedPassword, inputMd5, System.StringComparison.OrdinalIgnoreCase);              if (!passwordMatch)             {                 ModelState.AddModelError(string.Empty, "Email hoặc mật khẩu không đúng.");                 return View(model);             }              var userId = row.CustomerID.ToString();             var displayName = (row.CustomerName ?? model.Email) as string;             var userNameForClaim = (row.Email ?? model.Email) as string;              var claims = new[]             {                 new Claim(ClaimTypes.NameIdentifier, userId ?? string.Empty),                 new Claim(ClaimTypes.Name, userNameForClaim ?? string.Empty),                 new Claim(ClaimTypes.Email, userNameForClaim ?? string.Empty),                 new Claim("DisplayName", displayName ?? string.Empty),                 new Claim(ClaimTypes.Role, "Customer")             };              var identity = new ClaimsIdentity(claims, CookieAuthenticationDefaults.AuthenticationScheme);             var principal = new ClaimsPrincipal(identity);              await HttpContext.SignInAsync(CookieAuthenticationDefaults.AuthenticationScheme, principal);              if (!string.IsNullOrEmpty(model?.ReturnUrl) && Url.IsLocalUrl(model.ReturnUrl))                 return Redirect(model.ReturnUrl);              return RedirectToAction("Index", "Home");         }          /// <summary>         /// Đăng ký         /// </summary>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> Register()         {             var provincesRepo = new ProvinceRepository(Configuration.ConnectionString);             var provinces = await provincesRepo.ListAsync();             ViewBag.Provinces = provinces;             var vm = new SV22T1020494.Shop.Models.RegisterViewModel();             return View(vm);         }         /// <summary>         /// POST Đăng ký         /// </summary>         /// <param name="model"></param>         /// <returns></returns>         [HttpPost]         [ValidateAntiForgeryToken]         public async Task<IActionResult> Register(SV22T1020494.Shop.Models.RegisterViewModel model)         {             if (model == null || string.IsNullOrWhiteSpace(model.CustomerName) || string.IsNullOrWhiteSpace(model.Password)                 || string.IsNullOrWhiteSpace(model.Email) || string.IsNullOrWhiteSpace(model.Phone) || string.IsNullOrWhiteSpace(model.Province))             {                 ModelState.Clear();                 ModelState.AddModelError(string.Empty, "Vui lòng điền đầy đủ thông tin bắt buộc.");                  var provincesRepoErr = new ProvinceRepository(Configuration.ConnectionString);                 ViewBag.Provinces = await provincesRepoErr.ListAsync();                  return View(model);             }              var exists = await _customerAccountRepo.EmailExistsAsync(model.Email);             if (exists)             {                 ModelState.AddModelError(string.Empty, "Email đã được sử dụng.");                  var provincesRepoErr2 = new ProvinceRepository(Configuration.ConnectionString);                 ViewBag.Provinces = await provincesRepoErr2.ListAsync();                  return View(model);             }              var id = await _customerAccountRepo.CreateCustomerAsync(                 model.CustomerName,                 model.ContactName,                 model.Province,                 model.Address,                 model.Phone,                 model.Email,                 model.Password             );              if (id > 0)             {                 // Do not auto-login the newly registered user. Instead show a success notification                 // and ask them to go back to login to sign in with the new account.                 TempData["RegisterSuccess"] = "Đăng ký thành công! Hãy quay về đăng nhập để đăng nhập tài khoản mới này.";                 return RedirectToAction("Register");             }              ModelState.AddModelError(string.Empty, "Đăng ký thất bại.");              var provincesRepoErr3 = new ProvinceRepository(Configuration.ConnectionString);             ViewBag.Provinces = await provincesRepoErr3.ListAsync();              return View(model);         }          /// <summary>         /// Quản lý tài khoản         /// </summary>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> AccountInfo()         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              var idClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;             if (!int.TryParse(idClaim, out var id))                 return RedirectToAction("Login");              var row = await _customerAccountRepo.GetCustomerByIdAsync(id);             if (row == null) return RedirectToAction("Login");              ViewBag.Customer = row;             try             {                 var provincesRepo = new ProvinceRepository(Configuration.ConnectionString);                 var provinces = await provincesRepo.ListAsync();                 ViewBag.Provinces = provinces;             }             catch             {                 ViewBag.Provinces = null;             }             return View();         }          /// <summary>         /// Đổi mật khẩu         /// </summary>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> ChangePassword()         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              return View();         }          /// <summary>         /// Xem lịch sử mua hàng         /// </summary>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> Order()         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              var idClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;             int customerId;             if (!int.TryParse(idClaim, out customerId))             {                 var emailClaim = User.FindFirst(ClaimTypes.Email)?.Value ?? User.FindFirst(ClaimTypes.Name)?.Value;                 if (string.IsNullOrWhiteSpace(emailClaim))                     return RedirectToAction("Login");                  var cid = await _customerAccountRepo.GetCustomerIdByEmailAsync(emailClaim);                 if (!cid.HasValue)                     return RedirectToAction("Login");                  customerId = cid.Value;             }              var input = new SV22T1020494.Models.Sales.OrderSearchInput { Page = 1, PageSize = 0, CustomerID = customerId };             var result = await SV22T1020494.BusinessLayers.SalesDataService.ListOrdersAsync(input);             var orders = (result.DataItems ?? new List<SV22T1020494.Models.Sales.OrderViewInfo>())                 .OrderByDescending(o => o.OrderID)                 .ToList();              foreach (var o in orders)             {                 if (o.OrderID > 0)                 {                     try                     {                         o.OrderDetails = await SV22T1020494.BusinessLayers.SalesDataService.ListDetailsAsync(o.OrderID);                         if (o.OrderDetails != null && o.OrderDetails.Any())                         {                             foreach (var d in o.OrderDetails)                             {                                 try                                 {                                     var prod = await SV22T1020494.BusinessLayers.CatalogDataService.GetProductAsync(d.ProductID);                                     if (prod != null)                                     {                                         d.ProductName = prod.ProductName ?? (prod.ProductName ?? string.Empty);                                         d.Photo = prod.Photo ?? string.Empty;                                     }                                 }                                 catch { }                             }                         }                     }                     catch { }                 }             }              ViewBag.Orders = orders;             return View();         }         /// <summary>         /// POST đăng ký         /// </summary>         /// <param name="model"></param>         /// <returns></returns>         [HttpPost]         [ValidateAntiForgeryToken]         public async Task<IActionResult> ChangePassword(SV22T1020494.Shop.Models.ChangePasswordViewModel model)         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              var idClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;             if (!int.TryParse(idClaim, out var id))                 return RedirectToAction("Login");              if (model == null || string.IsNullOrWhiteSpace(model.OldPassword) || string.IsNullOrWhiteSpace(model.NewPassword) || string.IsNullOrWhiteSpace(model.ConfirmPassword))             {                 TempData["ChangePwdMsg"] = "Vui lòng điền đầy đủ thông tin.";                 return RedirectToAction("ChangePassword");             }              if (model.NewPassword != model.ConfirmPassword)             {                 TempData["ChangePwdMsg"] = "Mật khẩu mới và xác nhận không khớp.";                 return RedirectToAction("ChangePassword");             }              var stored = await _customerAccountRepo.GetCustomerPasswordAsync(id);             stored = stored ?? string.Empty;              string ComputeMd5(string s)             {                 using var md5 = MD5.Create();                 var bytes = Encoding.UTF8.GetBytes(s);                 var hash = md5.ComputeHash(bytes);                 var sb = new StringBuilder();                 foreach (var b in hash) sb.Append(b.ToString("x2"));                 return sb.ToString();             }              var oldMd5 = ComputeMd5(model.OldPassword);             var oldMatches = string.Equals(stored, model.OldPassword, System.StringComparison.Ordinal)                 || string.Equals(stored, oldMd5, System.StringComparison.OrdinalIgnoreCase);              if (!oldMatches)             {                 TempData["ChangePwdMsg"] = "Mật khẩu cũ không đúng.";                 return RedirectToAction("ChangePassword");             }              var emailClaim = User.FindFirst(ClaimTypes.Email)?.Value;             if (!string.IsNullOrWhiteSpace(emailClaim))             {                 await _customerAccountRepo.ChangePasswordAsync(emailClaim, model.NewPassword);             }              TempData["ChangePwdMsg"] = "Đổi mật khẩu thành công.";             return RedirectToAction("ChangePassword");         }          /// <summary>         /// Hàm để cập nhật thông tin trong quản lý tài khoản         /// </summary>         /// <param name="customerName"></param>         /// <param name="contactName"></param>         /// <param name="phone"></param>         /// <param name="province"></param>         /// <param name="address"></param>         /// <returns></returns>         [HttpPost]         [ValidateAntiForgeryToken]         public async Task<IActionResult> UpdateProfile(string customerName, string contactName, string phone, string province, string address)         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              var idClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;             if (!int.TryParse(idClaim, out var id))                 return RedirectToAction("Login");             if (string.IsNullOrWhiteSpace(customerName) || string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(province) || string.IsNullOrWhiteSpace(address))             {                 TempData["AccountMsg"] = "Vui lòng điền đầy đủ thông tin bắt buộc.";                 return RedirectToAction("AccountInfo");             }              await _customerAccountRepo.UpdateCustomerAsync(id, customerName, contactName, phone, province, address);              TempData["AccountMsg"] = "Cập nhật thông tin thành công.";             return RedirectToAction("AccountInfo");         }          /// <summary>         /// Đăng xuất         /// </summary>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> Logout()         {             await HttpContext.SignOutAsync(CookieAuthenticationDefaults.AuthenticationScheme);             return RedirectToAction("Index", "Home");         }          /// <summary>         /// Xem trạng thái đơn hàng         /// </summary>         /// <param name="id"></param>         /// <returns></returns>         [HttpGet]         public async Task<IActionResult> OrderStatus(int id)         {             if (!User.Identity.IsAuthenticated)                 return RedirectToAction("Login");              var order = await SV22T1020494.BusinessLayers.SalesDataService.GetOrderAsync(id);             if (order == null) return NotFound();              var idClaim = User.FindFirst(ClaimTypes.NameIdentifier)?.Value;             if (int.TryParse(idClaim, out var customerId))             {                 if (order.CustomerID.HasValue && order.CustomerID.Value != customerId)                 {                     return Forbid();                 }             }              try             {                 order.OrderDetails = await SV22T1020494.BusinessLayers.SalesDataService.ListDetailsAsync(order.OrderID);             }             catch { }              return View(order);         }     } } 